  1→import { lazy, Suspense } from 'react'
  2→import './App.css'
  3→import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
  4→import { useAuth } from './Context/useAuth.js';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  7→import ImageNode from './components/HomePage/Editor/nodes/ImageNode.jsx';
  8→import MentionNode from './components/HomePage/Editor/nodes/MentionNode.jsx';
  9→import Loader from './components/loadingComponent/BgLoader.jsx';
 10→import SeoManager from './seo/SeoManager.jsx';
 11→import ProtectedRoute from './components/ProtectedRoute.jsx';
 12→
 13→const NotFound = lazy(() => import('./components/NotFound.jsx'));
 14→
 15→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 16→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 17→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 18→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 19→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 20→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 21→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 22→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 23→const Visitprofile = lazy(() => import('./components/VisitProfile/Visitprofile.jsx'));
 24→const ProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx'));
 25→const ProfileMediaSection = lazy(() => import('./components/ProfilePage/components/ProfileMediaSection.jsx'));
 26→const VisitedProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/VisitedProfilePostCards.jsx'));
 27→const VisitedProfileMediaSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileMediaSection.jsx'));
 28→const Notifications = lazy(() => import('./components/Notifications/Notifications.jsx'));
 29→const NotificationCards = lazy(() => import('./components/Notifications/notificationsCards.jsx'));
 30→const UnreadNotification = lazy(() => import('./components/Notifications/UnreadNotificationCard.jsx'));
 31→const OpinionsPage = lazy(() => import('./components/SidebarOpinions/OpinionssPage.jsx'));
 32→const VisitedProfileOpinions = lazy(() => import('./components/SidebarOpinions/visitedProfileOpinions.jsx'));
 33→const MyOpinions = lazy(() => import('./components/SidebarOpinions/MyOpinions.jsx'));
 34→const OpinionViewer = lazy(() => import('./components/SidebarOpinions/opinionViewer.jsx'));
 35→const ExplorePage = lazy(() => import('./components/HomePage/explore/ExplorePage.jsx'));
 36→const SettingsPage = lazy(() => import('./components/SettingsPage/SettingsPage.jsx'));
 37→const DraftList = lazy(() => import('./components/HomePage/Editor/DraftList/DraftList.jsx'));
 38→const AnalyticsDashboard = lazy(() => import('./components/Analytics/AnalyticsDashboard.jsx'));
 39→const StoryDashboard = lazy(() => import('./components/Stories/StoryDashboard/StoryDashboard.jsx'));
 40→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 41→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 42→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 43→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 44→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 45→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 46→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 47→const ProfileStoriesSection = lazy(() => import('./components/ProfilePage/components/ProfileStoriesSection.jsx'));
 48→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 49→
 50→const editorTheme = {
 51→  paragraph: 'editor-paragraph',
 52→  heading: {
 53→    h1: 'editor-heading-h1',
 54→    h2: 'editor-heading-h2',
 55→    h3: 'editor-heading-h3',
 56→  },
 57→  quote: 'editor-quote',
 58→  text: {
 59→    bold: 'editor-text-bold',
 60→    italic: 'editor-text-italic',
 61→    underline: 'editor-text-underline',
 62→  }
 63→};
 64→
 65→const editorConfig = {
 66→  namespace: "MyLexicalEditor",
 67→  theme: editorTheme,
 68→  nodes: [ImageNode, HeadingNode, QuoteNode, MentionNode],
 69→  onError(error){
 70→    throw error;
 71→  },
 72→};
 73→
 74→const AppAuthModal = () => {
 75→  const {showAuthModal, closeAuthModal} = useAuth();
 76→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 77→}
 78→
 79→const AppSplash = () => {
 80→  const { loading } = useAuth();
 81→  return <Loader isLoading={loading} />;
 82→}
 83→
 84→const HomeWithEditor = () => (
 85→  <LexicalComposer initialConfig={editorConfig}>
 86→    <HomePage/>
 87→  </LexicalComposer>
 88→);
 89→
 90→const SuspenseFallback = () => (
 91→  <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
 92→    <Loader />
 93→  </div>
 94→);
 95→
 96→const App = () => {
 97→
 98→  return (
 99→    <>
100→      <BrowserRouter>
101→        <SeoManager />
102→        <AppSplash />
103→        <Suspense fallback={<SuspenseFallback />}>
104→          <AppAuthModal/>
105→          <Routes>
106→            <Route path='/' element={<Navigate to='/home' replace/>}/>
107→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
108→            <Route path='/profile' element={<ProtectedRoute><MyProfile/></ProtectedRoute>}>
109→              <Route index element={<ProfilePostCards/>} />
110→              <Route path='media' element={<ProfileMediaSection/>} />
111→              <Route path='myOpinions' element={<MyOpinions/>}/>
112→              <Route path='stories' element={<ProfileStoriesSection/>}/>
113→            </Route>
114→
115→            <Route path='/visitProfile' element={<Visitprofile/>}>
116→              <Route index element={<VisitedProfilePostCards/>}/>
117→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
118→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
119→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
120→            </Route>
121→
122→            <Route path='/u/:username' element={<Visitprofile/>}>
123→              <Route index element={<VisitedProfilePostCards/>}/>
124→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
125→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
126→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
127→            </Route>
128→
129→            <Route path='/home' element={<HomeWithEditor/>}>
130→              <Route index element={<PostCards/>}/>
131→              <Route path='following' element={<PostCards/>}/>
132→              <Route path='for-you' element={<PostCards/>}/>
133→              <Route path='explore' element={<ExplorePage/>}/>
134→              <Route path='contentViewer' element={<ContentView/>}/>
135→              <Route path='post/:journalId' element={<ContentView/>}/>
136→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
137→              <Route path='bookmark' element={<Bookmarks/>}/>
138→              <Route path='opinions'element={<OpinionsPage/>}/>
139→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
140→
141→              <Route path='drafts' element={<DraftList/>}/>
142→              <Route path='analytics' element={<AnalyticsDashboard/>}/>
143→              <Route path='settings' element={<SettingsPage/>}/>
144→
145→              {/* Stories routes */}
146→              <Route path='stories' element={<StoryBrowser/>}/>
147→              <Route path='stories/library' element={<StoryLibrary/>}/>
148→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
149→              <Route path='stories/new' element={<StoryEditor/>}/>
150→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
151→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
152→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
153→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
154→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
155→
156→              {/* route for nested notifications */}
157→              <Route path='notifications' element={<Notifications/>}>
158→                <Route index element={<NotificationCards/>}/>
159→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
160→              </Route>
161→            </Route>
162→
163→            <Route path='/login' element={<LoginPage/>}/>
164→            <Route path='/signUp' element={<SignUp/>}/>
165→            <Route path='*' element={<NotFound/>}/>
166→          </Routes>
167→        </Suspense>
168→      </BrowserRouter>
169→    </>
170→  )
171→}
172→
173→export default App
