  1→import { useCallback, useEffect, useRef, useState } from "react";
  2→
  3→import {
  4→  FORMAT_TEXT_COMMAND,
  5→  FORMAT_ELEMENT_COMMAND,
  6→  $getSelection,
  7→  $isRangeSelection,
  8→  $createParagraphNode,
  9→} from "lexical";
 10→
 11→import { $createHeadingNode, $isHeadingNode, $createQuoteNode, $isQuoteNode } from "@lexical/rich-text";
 12→import { $getSelectionStyleValueForProperty, $patchStyleText, $setBlocksType } from "@lexical/selection";
 13→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
 14→
 15→import { INSERT_IMAGE_COMMAND } from "./nodes/ImageNode";
 16→import { saveJournalImage } from "../../../../API/Api";
 17→import { useAuth } from "../../../Context/useAuth";
 18→
 19→const DEFAULT_ACTIVE_STATES = {
 20→    bold: false,
 21→    italic: false,
 22→    underline: false,
 23→    heading: null,
 24→    quote: false,
 25→    alignment: 'left',
 26→    textColor: '',
 27→    highlightColor: '',
 28→};
 29→
 30→const ToolBar = ({addUploadedImagePath}) =>{
 31→    const [editor] = useLexicalComposerContext();
 32→    const {session} = useAuth();
 33→    const colorPickerRef = useRef(null);
 34→
 35→    // Active state tracking
 36→    const [activeStates, setActiveStates] = useState(DEFAULT_ACTIVE_STATES);
 37→
 38→    const [showTextColorPicker, setShowTextColorPicker] = useState(false);
 39→    const [showHighlightColorPicker, setShowHighlightColorPicker] = useState(false);
 40→
 41→    const COLOR_PALETTE = [
 42→        { label: 'Default', value: null },
 43→        { label: 'Black', value: '#000000' },
 44→        { label: 'Dark Gray', value: '#4d4d4d' },
 45→        { label: 'Gray', value: '#888888' },
 46→        { label: 'Light Gray', value: '#bfbfbf' },
 47→        { label: 'Red', value: '#f44336' },
 48→        { label: 'Pink', value: '#e91e63' },
 49→        { label: 'Purple', value: '#9c27b0' },
 50→        { label: 'Deep Purple', value: '#673ab7' },
 51→        { label: 'Indigo', value: '#3f51b5' },
 52→        { label: 'Blue', value: '#2196f3' },
 53→        { label: 'Light Blue', value: '#03a9f4' },
 54→        { label: 'Cyan', value: '#00bcd4' },
 55→        { label: 'Teal', value: '#009688' },
 56→        { label: 'Green', value: '#4caf50' },
 57→        { label: 'Light Green', value: '#8bc34a' },
 58→        { label: 'Lime', value: '#cddc39' },
 59→        { label: 'Yellow', value: '#ffeb3b' },
 60→        { label: 'Amber', value: '#ffc107' },
 61→        { label: 'Orange', value: '#ff9800' },
 62→        { label: 'Deep Orange', value: '#ff5722' },
 63→        { label: 'Brown', value: '#795548' },
 64→        { label: 'Blue Gray', value: '#607d8b' },
 65→    ];
 66→
 67→    const toCompactRgb = (value) => {
 68→        if (!value) return '';
 69→        return value.toLowerCase().replace(/\s+/g, '');
 70→    };
 71→
 72→    const normalizeColor = (value) => {
 73→        if (!value) return '';
 74→        const trimmed = value.trim().toLowerCase();
 75→        if (!trimmed.startsWith('#')) {
 76→            return toCompactRgb(trimmed);
 77→        }
 78→
 79→        let hex = trimmed.slice(1);
 80→        if (hex.length === 3) {
 81→            hex = hex.split('').map((char) => `${char}${char}`).join('');
 82→        }
 83→        if (hex.length !== 6) {
 84→            return trimmed;
 85→        }
 86→
 87→        const r = parseInt(hex.slice(0, 2), 16);
 88→        const g = parseInt(hex.slice(2, 4), 16);
 89→        const b = parseInt(hex.slice(4, 6), 16);
 90→
 91→        return `rgb(${r},${g},${b})`;
 92→    };
 93→
 94→    const isPaletteColorActive = (activeValue, paletteValue) => {
 95→        const normalizedActive = normalizeColor(activeValue);
 96→        if (!paletteValue) {
 97→            return !normalizedActive;
 98→        }
 99→        return normalizedActive === normalizeColor(paletteValue);
100→    };
101→
102→    // Register update listener for active state detection
103→    useEffect(() => {
104→        return editor.registerUpdateListener(({ editorState }) => {
105→            editorState.read(() => {
106→                const selection = $getSelection();
107→                if (!$isRangeSelection(selection)) {
108→                    setActiveStates(DEFAULT_ACTIVE_STATES);
109→                    return;
110→                }
111→
112→                const bold = selection.hasFormat('bold');
113→                const italic = selection.hasFormat('italic');
114→                const underline = selection.hasFormat('underline');
115→
116→                const anchorNode = selection.anchor.getNode();
117→                let element;
118→                try {
119→                    element = anchorNode.getKey() === 'root'
120→                        ? anchorNode
121→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
122→                } catch {
123→                    element = null;
124→                }
125→
126→                let heading = null;
127→                let quote = false;
128→                let alignment = 'left';
129→
130→                if (element) {
131→                    if ($isHeadingNode(element)) {
132→                        heading = element.getTag(); // 'h1', 'h2', 'h3'
133→                    }
134→                    if ($isQuoteNode(element)) {
135→                        quote = true;
136→                    }
137→                    const formatType = element.getFormatType?.();
138→                    if (formatType) {
139→                        alignment = formatType;
140→                    }
141→                }
142→
143→                const textColor = $getSelectionStyleValueForProperty(selection, 'color', '');
144→                const highlightColor = $getSelectionStyleValueForProperty(selection, 'background-color', '');
145→
146→                setActiveStates({
147→                    bold,
148→                    italic,
149→                    underline,
150→                    heading,
151→                    quote,
152→                    alignment,
153→                    textColor,
154→                    highlightColor,
155→                });
156→            });
157→        });
158→    }, [editor]);
159→
160→    useEffect(() => {
161→        const handleClickOutside = (event) => {
162→            if (!colorPickerRef.current) return;
163→            if (!colorPickerRef.current.contains(event.target)) {
164→                setShowTextColorPicker(false);
165→                setShowHighlightColorPicker(false);
166→            }
167→        };
168→        document.addEventListener('mousedown', handleClickOutside);
169→        return () => document.removeEventListener('mousedown', handleClickOutside);
170→    }, []);
171→
172→
173→    const applyTextFormat = (format) => {
174→        editor.dispatchCommand(FORMAT_TEXT_COMMAND, format)
175→    }
176→
177→    const applyTextStyle = useCallback((styles) => {
178→        const sanitizedStyles = Object.fromEntries(
179→            Object.entries(styles).map(([key, value]) => [key, value ?? ''])
180→        );
181→        editor.update(() => {
182→            const selection = $getSelection();
183→            if ($isRangeSelection(selection)) {
184→                $patchStyleText(selection, sanitizedStyles);
185→            }
186→        });
187→    }, [editor]);
188→
189→    //heading node (H1, H2, H3)
190→    const setHeading = (tag) => {
191→        editor.update(() => {
192→            const selection = $getSelection();
193→            if ($isRangeSelection(selection)) {
194→                const anchorNode = selection.anchor.getNode();
195→
196→                let element;
197→                try {
198→                    element = anchorNode.getKey() === 'root'
199→                        ? anchorNode
200→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
201→                } catch (e) {
202→                    console.error('Could not get top level element:', e);
203→                    return;
204→                }
205→
206→                if (!element) return;
207→
208→                const type = typeof element.getType === 'function' ? element.getType() : null;
209→
210→                if (type && type !== "paragraph" && type !== "heading" && type !== "root") {
211→                    return;
212→                }
213→
214→                const isActive = $isHeadingNode(element) && element.getTag() === tag;
215→
216→                $setBlocksType(selection, () =>
217→                    isActive ? $createParagraphNode() : $createHeadingNode(tag)
218→                );
219→            }
220→        })
221→    }
222→
223→    //align element
224→    const setAlignment = (value) => {
225→        editor.dispatchCommand(FORMAT_ELEMENT_COMMAND, value);
226→    }
227→
228→    //quote block (toggle)
229→    const setQuote = () => {
230→        editor.update(() => {
231→            const selection = $getSelection();
232→            if ($isRangeSelection(selection)) {
233→                const anchorNode = selection.anchor.getNode();
234→
235→                let element;
236→                try {
237→                    element = anchorNode.getKey() === 'root'
238→                        ? anchorNode
239→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
240→                } catch (e) {
241→                    console.error('Could not get top level element:', e);
242→                    return;
243→                }
244→
245→                if (!element) return;
246→
247→                const type = typeof element.getType === 'function' ? element.getType() : null;
248→                if (type && type !== "paragraph" && type !== "heading" && type !== "quote" && type !== "root") {
249→                    return;
250→                }
251→
252→                const isActive = $isQuoteNode(element);
253→
254→                $setBlocksType(selection, () =>
255→                    isActive ? $createParagraphNode() : $createQuoteNode()
256→                );
257→            }
258→        })
259→    }
260→
261→    //insert image
262→    const insertImageFromFile = async() => {
263→
264→        const handleOnChange = async(e) => {
265→            const filedata = e.target.files?.[0];
266→            if(!filedata) return;
267→
268→            const blobUrl = URL.createObjectURL(filedata);
269→
270→            editor.dispatchCommand(INSERT_IMAGE_COMMAND, {
271→                src: blobUrl,
272→                width: 500,
273→                height: 500,
274→                loading: true,
275→            })
276→
277→            const formdata = new FormData();
278→            formdata.append('image', filedata);
279→
280→            try {
281→                const data_url = await saveJournalImage(session?.access_token, formdata);
282→                if(!data_url){
283→                    // console.log('error: no image_url');
284→                    return;
285→                }
286→
287→                const filePath = data_url.img_url.split('/journal-images/').pop();
288→                if (filePath && addUploadedImagePath) {
289→                    addUploadedImagePath(filePath);
290→                }
291→
292→                editor.update(() => {
293→                    const root = editor.getEditorState()._nodeMap;
294→                    for (const [, node] of root) {
295→                        if (node.__type === 'image' && node.__src === blobUrl) {
296→                            node.getWritable().__src = data_url.img_url;
297→                            node.getWritable().__loading = false;
298→                            break;
299→                        }
300→                    }
301→                });
302→
303→                URL.revokeObjectURL(blobUrl);
304→            } catch (err) {
305→                console.error('Image upload failed:', err);
306→            }
307→        }
308→
309→        const input = document.createElement('input');
310→        input.type = 'file'
311→        input.accept = 'image/*';
312→        input.onchange = (e) => {handleOnChange(e)}
313→
314→        input.click();
315→    };
316→
317→    // Helper to get class name based on active state
318→    const getBtnClass = (isActive) => isActive ? 'is-active' : 'toolbar-bttns';
319→
320→    return(
321→        <div className="toolbar">
322→            {/* Group 1: Image upload */}
323→            <div className="group">
324→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => insertImageFromFile()} className="toolbar-bttns" title="Insert image">
325→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M480-480ZM200-120q-33 0-56.5-23.5T120-200v-560q0-33 23.5-56.5T200-840h320v80H200v560h560v-320h80v320q0 33-23.5 56.5T760-120H200Zm40-160h480L570-480 450-320l-90-120-120 160Zm440-320v-80h-80v-80h80v-80h80v80h80v80h-80v80h-80Z"/></svg>
326→                </div>
327→            </div>
328→
329→            <div className="toolbar-divider" />
330→
331→            {/* Group 2: Text formatting */}
332→            <div className="group">
333→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => applyTextFormat('bold')} className={getBtnClass(activeStates.bold)} title="Bold">
334→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M272-200v-560h221q65 0 120 40t55 111q0 51-23 78.5T602-491q25 11 55.5 41t30.5 90q0 89-65 124.5T501-200H272Zm121-112h104q48 0 58.5-24.5T566-372q0-11-10.5-35.5T494-432H393v120Zm0-228h93q33 0 48-17t15-38q0-24-17-39t-44-15h-95v109Z"/></svg>
335→                </div>
336→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => applyTextFormat('italic')} className={getBtnClass(activeStates.italic)} title="Italic">
337→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M200-200v-100h160l120-360H320v-100h400v100H580L460-300h140v100H200Z"/></svg>
338→                </div>
339→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => applyTextFormat('underline')} className={getBtnClass(activeStates.underline)} title="Underline">
340→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M200-120v-80h560v80H200Zm280-160q-101 0-157-63t-56-167v-330h103v336q0 56 28 91t82 35q54 0 82-35t28-91v-336h103v330q0 104-56 167t-157 63Z"/></svg>
341→                </div>
342→            </div>
343→
344→            <div className="toolbar-divider" />
345→
346→            {/* Group 3: Headings */}
347→            <div className="group">
348→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => setHeading('h1')} className={getBtnClass(activeStates.heading === 'h1')} title="Heading 1">
349→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M200-280v-400h80v160h160v-160h80v400h-80v-160H280v160h-80Zm480 0v-320h-80v-80h160v400h-80Z"/></svg>
350→                </div>
