199→    margin-bottom: 0;
200→    position: sticky;
201→    top: 0;
202→    z-index: 5;
203→    background-color: var(--editor-bg);
204→}
205→.toolbar {
206→    display: flex;
207→    align-items: center;
208→    gap: 2px;
209→    width: 100%;
210→    flex-wrap: wrap;
211→}
212→.group {
213→    display: flex;
214→    align-items: center;
215→    gap: 2px;
216→}
217→.toolbar-divider {
218→    width: 1px;
219→    height: 20px;
220→    background-color: var(--editor-border);
221→    margin: 0 6px;
222→    flex-shrink: 0;
223→}
224→.toolbar-bttns {
225→    display: flex;
226→    width: fit-content;
227→    height: fit-content;
228→    justify-content: center;
229→    align-items: center;
