557→    display: flex;
558→    justify-content: flex-end;
559→    margin: 1rem 0;
560→    width: fit-content;
561→    height: fit-content;
562→}
563→.image-actions {
564→    position: absolute;
565→    display: flex;
566→    gap: 0.3rem;
567→    top: 0;
568→    right: 0;
569→    margin: 0.5rem;
570→    z-index: 11;
571→}
572→.image-action-btn {
573→    display: flex;
574→    align-items: center;
575→    justify-content: center;
576→    padding: 0.4rem;
577→    border-radius: 50%;
578→    cursor: pointer;
