### Phase 4 — Links: LinkPlugin + AutoLinkPlugin + FloatingLinkEditor

**Goal:** Users can insert/edit links. Mobile-friendly inline popup, not a modal.

**Step 4.1 — Add plugins to `RichTextEditor.jsx`**

```jsx
import { LinkPlugin } from '@lexical/react/LexicalLinkPlugin';
import { AutoLinkPlugin } from '@lexical/react/LexicalAutoLinkPlugin';

const URL_MATCHERS = [
  (text) => {
    const urlRegex = /((https?:\/\/(www\.)?)|(www\.))[-a-zA-Z0-9@:%._+~#=]{1,256}\.[a-zA-Z0-9()]{1,6}\b([-a-zA-Z0-9()@:%_+.~#?&//=]*)/;
    const match = urlRegex.exec(text);
    if (!match) return null;
    const fullMatch = match[0];
    return {
      index: match.index,
      length: fullMatch.length,
      text: fullMatch,
      url: fullMatch.startsWith('http') ? fullMatch : `https://${fullMatch}`,
    };
  },
];

// Inside editor-shell:
<LinkPlugin validateUrl={(url) => url.startsWith('http://') || url.startsWith('https://')} />
<AutoLinkPlugin matchers={URL_MATCHERS} />
```

**Step 4.2 — Create `FloatingLinkEditor.jsx`**

New file: `client/src/components/HomePage/Editor/plugins/FloatingLinkEditor.jsx`

This is the most complex piece of Phase 4. The component:
1. Listens to editor selection changes
2. When a `LinkNode` is selected (or cursor is inside a link), it positions a popup below the selected text
3. The popup shows: a URL input field, a confirm/save button, an "open in new tab" button (external link icon), and a remove/unlink button
4. For new links, when text is selected and the user clicks the link button in the toolbar, the popup opens with an empty URL field

Key implementation notes:
- Use `editor.registerUpdateListener` to detect when cursor is inside a link
- Use `$getSelection()` and `$findMatchingParent(node, $isLinkNode)` from `@lexical/utils` to detect link context
- Position using `editor.getRootElement().getBoundingClientRect()` and the selection's DOM range `getBoundingClientRect()`
- Use `TOGGLE_LINK_COMMAND` from `@lexical/link` to create or update links
- The popup must `onMouseDown={(e) => e.preventDefault()}` on all interactive elements to prevent focus loss

The popup renders via a `ReactDOM.createPortal` to `document.body` so it escapes the editor's `overflow: hidden` container.

Rough structure:
```jsx
// FloatingLinkEditor.jsx
import { createPortal } from 'react-dom';
import { $getSelection, $isRangeSelection } from 'lexical';
import { $isLinkNode, TOGGLE_LINK_COMMAND } from '@lexical/link';
import { $findMatchingParent } from '@lexical/utils';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { useEffect, useRef, useState, useCallback } from 'react';

export default function FloatingLinkEditorPlugin() {
  const [editor] = useLexicalComposerContext();
  const [linkUrl, setLinkUrl] = useState('');
  const [isEditing, setIsEditing] = useState(false);
  const [floatCoords, setFloatCoords] = useState(null);
  const [linkNode, setLinkNode] = useState(null);
  const inputRef = useRef(null);

  // ... listener logic ...

  if (!floatCoords || !isEditing) return null;

  return createPortal(
    <div
      className="floating-link-editor"
      style={{ top: floatCoords.y, left: floatCoords.x }}
      onMouseDown={(e) => e.preventDefault()}
    >
      <input
        ref={inputRef}
        value={linkUrl}
        onChange={(e) => setLinkUrl(e.target.value)}
        onKeyDown={(e) => { if (e.key === 'Enter') confirmLink(); }}
        placeholder="https://..."
        className="floating-link-input"
      />
      <div className="floating-link-actions">
        <button onClick={confirmLink}>Save</button>
        <button onClick={openLink}>Open</button>
        <button onClick={removeLink}>Remove</button>
      </div>
    </div>,
    document.body
  );
}
```

